










































import Vue from 'vue';
import memberGroupCard from '@/components/workspace/MemberGroupCard.vue';
import EmptyHint from '@/components/workspace/EmptyHint.vue';
import ManagerApi from '@/apis/ManagerApi';
import { ManagerEntryInfoModel } from '@/apis/models/ManagerModel';
import { WorkspaceDataModel } from '@/apis/models/WorkspaceModel';
import MemberGroupApi from '@/apis/MemberGroupApi';
import { MemberGroupPreview, SharedMemberGroup } from '@/apis/models/MemberGroupModel';
import Auth from '@/libs/auth';
import ShareMappingApi from '@/apis/ShareMappingApi';
import { ResourceType } from '@/apis/models/ShareMappingModel';
import SharedObjectCard from '@/components/workspace/SharedObjectCard.vue';

export default Vue.extend({
  components: {
    memberGroupCard,
    SharedObjectCard,
    EmptyHint,
  },
  data() {
    return {
      sharedMemberGroups: [] as SharedMemberGroup[],
    };
  },
  computed: {
    currentWorkspace(): WorkspaceDataModel {
      return this.$store.state.currentWorkspace;
    },
    memberGroups(): MemberGroupPreview[] {
      return this.$store.state.theMemberGroups;
    },
  },
  async mounted() {
    Auth.loginCheck();

    // [Development] temperarily put manager info here
    await ManagerApi.getManagerEntryInfo().then((info: ManagerEntryInfoModel) => {
      this.$store.commit('updateWorkspaceList', info.workspaceList);
      this.$store.commit('changeWorkspace', info.workspaceList[0]);
      this.$store.commit('setUsername', info.username);
    });

    await ShareMappingApi.list(ResourceType.MEMBER_GROUP).then((memberGroups) => {
      this.sharedMemberGroups = memberGroups as SharedMemberGroup[];
    });

    await MemberGroupApi.getMemberGroups(this.currentWorkspace.uuid).then(
      (datalist) => {
        this.$store.commit('getMemberGroups', datalist);
      },
    );
  },
  methods: {
    async deleteGroupCard(index: number) {
      if (this.memberGroups) {
        if (index >= 0 && index < this.memberGroups.length) {
          await MemberGroupApi.deleteMemberGroup(this.currentWorkspace.uuid, this.memberGroups[index].uuid);
          this.memberGroups.splice(index, 1);
        }
      }
    },
  },
});
