import { ProfileModel } from './AccountModel';

export enum Permission {
  EDITOR = 'EDITOR' as any,
  DETAIL_VIEWER = 'DETAIL_VIEWER' as any,
  GENERAL_VIEWER = 'GENERAL_VIEWER' as any
}

export enum ResourceType {
  QUIZ_GROUP = 'quiz-groups' as any,
  MEMBER_GROUP = 'member-groups' as any,
}

export interface ShareMapping {
  uuid: string;
  owner: ProfileModel;
  receiver: ProfileModel;
  resourceId: string;
  permission: Permission;
}

export interface SharedObject {
  owner: ProfileModel;
  permission: Permission;
}

export class ShareMappingUpdatePayload {
  permission: Permission;

  constructor(permission: Permission) {
    this.permission = permission;
  }
}
