import api from '@/apis/BaseApi';
import {
  Permission, ResourceType, ShareMapping, ShareMappingUpdatePayload,
} from './models/ShareMappingModel';

/**
 * ShareMappingApiModule
 *
 * Modularized ShareMapping API,
 * should be embedded in workspace-resource API,
 * such as MemberGroupApi or QuizGroupApi.
 *
 */
export default class ShareMappingApiModule {
  resourceType: ResourceType;

  constructor(resourceType: ResourceType) {
    this.resourceType = resourceType;
  }

  async create(workspaceId: string, resourceId: string, receiverUsername: string, permission: Permission): Promise<ShareMapping> {
    const body = {
      receiverUsername,
      permission,
    };
    const result = await api.post(`workspace/${workspaceId}/${this.resourceType}/${resourceId}/share-mappings`, body);
    return result.data.shareMapping;
  }

  async list(workspaceId: string, resourceId: string): Promise<ShareMapping[]> {
    const result = await api.get(`workspace/${workspaceId}/${this.resourceType}/${resourceId}/share-mappings`);
    return result.data.shareMappings;
  }

  async update(workspaceId: string, resourceId: string, shareMappingId: string, updatePayload: ShareMappingUpdatePayload): Promise<ShareMapping> {
    const body = {
      ...updatePayload,
    };
    const result = await api.put(`workspace/${workspaceId}/${this.resourceType}/${resourceId}/share-mappings/${shareMappingId}`, body);
    return result.data.shareMapping;
  }

  async destroy(workspaceId: string, resourceId: string, shareMappingId: string): Promise<void> {
    await api.delete(`workspace/${workspaceId}/${this.resourceType}/${resourceId}/share-mappings/${shareMappingId}`);
  }
}
