





































import Vue, { PropType } from 'vue';
import { SharedQuizGroup } from '@/apis/models/QuizGroupModel';
import { Permission } from '@/apis/models/ShareMappingModel';
import { SharedMemberGroup } from '@/apis/models/MemberGroupModel';

export default Vue.extend({
  name: 'SharedObjectCard',
  components: {
  },
  props: {
    sharedObject: {
      type: Object as PropType<SharedMemberGroup | SharedQuizGroup>,
      required: true,
    },
    displayName: {
      type: String,
      required: false,
      default: '',
    },
    info: {
      type: String,
      required: false,
      default: '',
    },
  },
  data() {
    return {
    };
  },
  computed: {
    permissionText(): string {
      if (this.sharedObject) {
        switch (this.sharedObject.permission) {
          case Permission.EDITOR:
            return '可編輯';
          case Permission.DETAIL_VIEWER:
            return '可檢視';
          case Permission.GENERAL_VIEWER:
            return '可使用';
          default:
            return '無權限';
        }
      }
      return '無權限';
    },
    onwerText(): string {
      if (this.sharedObject && this.sharedObject.owner) {
        return this.sharedObject.owner.username;
      }
      return '未知';
    },
    displayNameText(): string {
      if (this.displayName) { // empty string is falsy too
        return this.displayName;
      }

      return this.sharedObject.name;
    },
    canViewDetail(): boolean {
      return (this.sharedObject.permission === Permission.EDITOR) || (this.sharedObject.permission === Permission.DETAIL_VIEWER);
    },
    canEdit(): boolean {
      return (this.sharedObject.permission === Permission.EDITOR);
    },
  },
  methods: {
  },
});
